import React, { Component } from 'react';
import SidebarProject from './../components/SidebarProject';
import { Spring } from 'react-spring/renderprops';
import './../components/project.css';
import { Link, useParams } from 'react-router-dom';

class ProjectPage extends Component {

  componentDidMount() {
    let id = this.props.match.params.id;
    const { projectName } = this.props.location.state;
    const { projectDesc } = this.props.location.state;
    const { projectImg } = this.props.location.state;
    console.log({ projectName, projectDesc, projectImg });

  }

  render() {
    return (
      <div>
        <SidebarProject />
        <h2>{ this.id }</h2>
        <h2> { this.props.match.params.projectName }</h2>
        </div>
    );
  }
}

export default ProjectPage;
